use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

pub type TimedMultisigDatum {
  required_signers: List<ByteArray>,
  threshold: Int,
  unlock_time: Int,
}

fn check_time(tx: Transaction, unlock_time: Int) -> Bool {
  when tx.validity_range.lower_bound.bound_type is {
    cardano/interval.{Finite(lower)} -> lower >= unlock_time
    _ -> False
  }
}

fn check_signers(
  tx: Transaction,
  required: List<ByteArray>,
  threshold: Int,
) -> Bool {
  let present =
    list.count(tx.extra_signatories, fn(sig) { list.has(required, sig) })
  present >= threshold
}

validator timed_multisig {
  spend(
    datum: Option<TimedMultisigDatum>,
    _redeemer: Data,
    _input: OutputReference,
    tx: Transaction,
  ) {
    when datum is {
      Some(d) -> {
        let time_ok =
          when tx.validity_range.lower_bound.bound_type is {
            cardano/interval.Finite(lower) -> lower >= d.unlock_time
            _ -> False
          }
        let signers_ok = check_signers(tx, d.required_signers, d.threshold)
        time_ok && signers_ok
      }
      None -> False
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

pub type Datum {
  signers: List<ByteArray>,
  threshold: Int,
  emergency_key: ByteArray,
  deadline: Int,
}

pub type Redeemer {
  Normal
  Emergency
}

validator emergency_multisig {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Normal -> {
            let present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(d.signers, sig) },
              )
            present >= d.threshold
          }
          Emergency -> {
            let after_deadline =
              when self.validity_range.lower_bound.bound_type is {
                cardano/transaction.Finite(t) -> t >= d.deadline
                _ -> False
              }
            let has_emergency_key =
              list.has(self.extra_signatories, d.emergency_key)
            after_deadline && has_emergency_key
          }
        }
    }
  }
}

use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

pub type DecayDatum {
  signers: List<ByteArray>,
  initial_threshold: Int,
  reduced_threshold: Int,
  decay_time: Int,
}

pub type DecayRedeemer {
  Void
}

fn get_lower_bound(tx: Transaction) -> Int {
  when tx.validity_range.lower_bound.bound_type is {
    cardano/transaction.Finite(t) -> t
    _ -> 0
  }
}

validator decaying_multisig {
  spend(
    datum: Option<DecayDatum>,
    _redeemer: DecayRedeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let now = get_lower_bound(self)
        let threshold =
          if now >= d.decay_time {
            d.reduced_threshold
          } else {
            d.initial_threshold
          }
        let present =
          list.count(
            self.extra_signatories,
            fn(sig) { list.has(d.signers, sig) },
          )
        present >= threshold
      }
    }
  }

  else(_) {
    False
  }
}

use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

pub type RecoveryDatum {
  owner: ByteArray,
  guardians: List<ByteArray>,
  guardian_threshold: Int,
  recovery_delay: Int,
}

pub type RecoveryRedeemer {
  OwnerSpend
  GuardianRecover { new_owner: ByteArray }
}

fn owner_can_spend(datum: RecoveryDatum, tx: Transaction) -> Bool {
  list.has(tx.extra_signatories, datum.owner)
}

fn guardians_can_recover(datum: RecoveryDatum, tx: Transaction) -> Bool {
  let present =
    list.count(
      tx.extra_signatories,
      fn(sig) { list.has(datum.guardians, sig) },
    )
  let threshold_met = present >= datum.guardian_threshold
  let delay_respected =
    when tx.validity_range.lower_bound.bound_type is {
      Finite(lower) -> lower >= datum.recovery_delay
      _ -> False
    }
  threshold_met && delay_respected
}

validator recovery_wallet {
  spend(
    datum: Option<RecoveryDatum>,
    redeemer: RecoveryRedeemer,
    _output_reference: OutputReference,
    tx: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          OwnerSpend -> owner_can_spend(d, tx)
          GuardianRecover { new_owner: _ } -> guardians_can_recover(d, tx)
        }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

pub type ExpiryDatum {
  signers: List<ByteArray>,
  threshold: Int,
  expiry: Int,
  fallback: ByteArray,
}

pub type ExpiryRedeemer {
  UseMultisig
  UseFallback
}

fn get_current_time(tx: Transaction) -> Int {
  let upper = tx.validity_range.upper
  when upper is {
    cardano/transaction.{Finite(t)} -> t
    _ -> 0
  }
}

validator expiring_multisig {
  spend(
    datum: Option<ExpiryDatum>,
    redeemer: ExpiryRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let current_time = get_current_time(self)
        when redeemer is {
          UseMultisig -> {
            let before_expiry = current_time < d.expiry
            let present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(d.signers, sig) },
              )
            before_expiry && present >= d.threshold
          }
          UseFallback -> {
            let after_expiry = current_time >= d.expiry
            let fallback_signed = list.has(self.extra_signatories, d.fallback)
            after_expiry && fallback_signed
          }
        }
      }
    }
  }
}

use aiken/collection/list
use cardano/assets.{lovelace_of}
use cardano/transaction.{OutputReference, Transaction}

pub type GuardDatum {
  signers: List<ByteArray>,
  threshold: Int,
  min_lovelace: Int,
}

pub type GuardRedeemer {
  recipient: ByteArray,
}

fn check_signers(
  required: List<ByteArray>,
  signatories: List<ByteArray>,
  threshold: Int,
) -> Bool {
  let present =
    list.count(signatories, fn(sig) { list.has(required, sig) })
  present >= threshold
}

fn check_min_lovelace(
  tx: Transaction,
  recipient: ByteArray,
  min_lovelace: Int,
) -> Bool {
  list.any(
    tx.outputs,
    fn(output) {
      let addr_matches =
        output.address.payment_credential == cardano/address.VerificationKey(
          recipient,
        )
      let value_ok = lovelace_of(output.value) >= min_lovelace
      addr_matches && value_ok
    },
  )
}

validator guarded_multisig {
  spend(
    datum: Option<GuardDatum>,
    redeemer: GuardRedeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let signers_ok =
          check_signers(d.signers, self.extra_signatories, d.threshold)
        let lovelace_ok =
          check_min_lovelace(self, redeemer.recipient, d.min_lovelace)
        signers_ok && lovelace_ok
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

pub type InheritanceDatum {
  owner: ByteArray,
  heirs: List<ByteArray>,
  heir_threshold: Int,
  inactivity_deadline: Int,
}

pub type InheritanceRedeemer {
  OwnerSpend
  HeirClaim
}

fn owner_signed(tx: Transaction, owner: ByteArray) -> Bool {
  list.has(tx.extra_signatories, owner)
}

fn heirs_threshold_met(
  tx: Transaction,
  heirs: List<ByteArray>,
  threshold: Int,
) -> Bool {
  let present =
    list.count(tx.extra_signatories, fn(sig) { list.has(heirs, sig) })
  present >= threshold
}

fn deadline_passed(tx: Transaction, deadline: Int) -> Bool {
  when tx.validity_range.lower_bound.bound_type is {
    transaction.Finite(lower) -> lower >= deadline
    _ -> False
  }
}

validator inheritance {
  spend(
    datum: Option<InheritanceDatum>,
    redeemer: InheritanceRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          OwnerSpend -> owner_signed(self, d.owner)
          HeirClaim ->
            heirs_threshold_met(self, d.heirs, d.heir_threshold) && deadline_passed(
              self,
              d.inactivity_deadline,
            )
        }
    }
  }

  else(_) {
    fail
  }
}
